from collections import Counter

class Solution(object):
    def minimumOperationsToWriteY(self, grid):
        n = len(grid)
        mid = n // 2
        y_cells = set()
        for r in range(mid + 1):
            y_cells.add((r, r))
            y_cells.add((r, n - 1 - r))
        for r in range(mid, n):
            y_cells.add((r, mid))

        y_count = Counter()
        non_y_count = Counter()
        for r in range(n):
            for c in range(n):
                v = grid[r][c]
                if (r, c) in y_cells:
                    y_count[v] += 1
                else:
                    non_y_count[v] += 1

        total_y = sum(y_count.values())
        total_non_y = sum(non_y_count.values())
        ans = float('inf')
        for cy in range(3):
            for cn in range(3):
                if cy == cn:
                    continue
                ops = (total_y - y_count[cy]) + (total_non_y - non_y_count[cn])
                ans = min(ans, ops)
        return ans
